//ctlUp.OnClick

System.Windows.Forms.CheckedListBox list = m_form.ctlOpList;
int sel = list.SelectedIndex;
if (sel > 0)
{
    object item = list.Items[sel];
    bool chk = list.GetItemChecked(sel);
    list.Items.RemoveAt(sel);
    sel--;
    list.Items.Insert(sel, item);
    list.SetItemChecked(sel, chk);
    list.SelectedIndex = sel;
}

//ctlDown.OnClick

System.Windows.Forms.CheckedListBox list = m_form.ctlOpList;
int sel = list.SelectedIndex;
if (sel >= 0 && sel < list.Items.Count-1)
{
    object item = list.Items[sel];
    bool chk = list.GetItemChecked(sel);
    list.Items.RemoveAt(sel);
    sel++;
    list.Items.Insert(sel, item);
    list.SetItemChecked(sel, chk);
    list.SelectedIndex = sel;
}

System.Windows.Forms.Control control =
    (System.Windows.Forms.Control) i_arg0;
string dest = control.Text.Trim().ToLower();

m_root.ErrorProvider.SetError(control, null);
i_arg1.Cancel = false;

if (dest.Length == 0 || dest == "any")
{
    return;
}

string errorAddress = null;
string errorNetwork = null;
try
{
    AddressFactory.CreateAddress(dest);
}
catch (Exception e)
{
    errorAddress = e.Message;
}
try
{
    AddressFactory.CreateNetwork(dest);
}
catch (Exception e)
{
    errorNetwork = e.Message;
} 

if (errorAddress != null && errorNetwork != null)
{
    m_root.ErrorProvider.SetError(control, errorNetwork);
    i_arg1.Cancel = true;
}

//SelectedIndexChanged

System.Windows.Forms.TabControl tab = m_form.ctlOpTab;
System.Windows.Forms.CheckedListBox list = m_form.ctlOpList;
clcs.PropertyStringList ops = m_object.operationOrder;

Hashtable opNames = new Hashtable();
opNames["kDelay"] = "Latency";
opNames["kDrop"] = "Random Packet Loss";
opNames["kDropSequence"] = "Sequential Packet Loss";
opNames["kReorder"] = "Reorder Using Time Delay";
opNames["kReorderPI"] = "Reorder Using Packet Interval";
opNames["kDuplicate"] = "Packet Duplication";
opNames["kBandwidth"] = "General Settings";

Hashtable opNamesRev = new Hashtable();
foreach (string key in opNames.Keys)
{
    opNamesRev[opNames[key]] = key;
}

ops.Clear();
foreach (object item in list.Items)
{
    string key = (string) opNamesRev[item.ToString()];
    if (key == null) continue;
    ops.Add(key);
 }

string pgname = (string) opNamesRev[list.Text];
foreach (System.Windows.Forms.TabPage pg in tab.TabPages)
{
    if (pg.Text == pgname)
    {
        pg.BorderStyle = System.Windows.Forms.BorderStyle.FixedSingle;
        tab.SelectedTab = pg;
        list.Focus();
        break;
    }
}

string kBandwidthName = opNames["kBandwidth"] as string;
m_form.ctlUp.Enabled = (list.Text != kBandwidthName && list.SelectedIndex>0);
m_form.ctlDown.Enabled = (list.Text != kBandwidthName && list.SelectedIndex<list.Items.Count-2);
m_form.ctlTabName.Text = " " + list.Text;
if (!list.Text.EndsWith("Settings"))
{
    m_form.ctlTabName.Text += " Settings";
}

//ItemCheck

System.Windows.Forms.CheckedListBox list = m_form.ctlOpList;

Hashtable opNames = new Hashtable();
opNames["kDelay"] = "Latency";
opNames["kDrop"] = "Random Packet Loss";
opNames["kDropSequence"] = "Sequential Packet Loss";
opNames["kReorder"] = "Reorder Using Time Delay";
opNames["kReorderPI"] = "Reorder Using Packet Interval";
opNames["kDuplicate"] = "Packet Duplication";
opNames["kBandwidth"] = "General Settings";

Hashtable opBinds = new Hashtable();
Type typeObject = m_object.GetType();
opBinds["kDelay"] = typeObject.GetProperty("addDelay");
opBinds["kDrop"] = typeObject.GetProperty("addDrop");
opBinds["kDropSequence"] = typeObject.GetProperty("addDropSequence");
opBinds["kReorder"] = typeObject.GetProperty("addReorder");
opBinds["kReorderPI"] = typeObject.GetProperty("addReorderPI");
opBinds["kDuplicate"] = typeObject.GetProperty("addDuplicate");
opBinds["kBandwidth"] = null;

Hashtable opNamesRev = new Hashtable();
foreach (string k in opNames.Keys)
{
    opNamesRev[opNames[k]] = k;
}

string name = list.Items[i_arg1.Index] as string;
string key = opNamesRev[name] as string;

PropertyInfo prop = opBinds[key] as PropertyInfo;
if (prop == null)
{
    i_arg1.NewValue = CheckState.Checked;
    return;
}

bool chk = (i_arg1.NewValue == CheckState.Checked);
prop.SetValue(m_object, chk, null);
CallSetters();

//Layout

System.Windows.Forms.CheckedListBox list = m_form.ctlOpList;
clcs.PropertyStringList ops = m_object.operationOrder;

Hashtable opNames = new Hashtable();
opNames["kDelay"] = "Latency";
opNames["kDrop"] = "Random Packet Loss";
opNames["kDropSequence"] = "Sequential Packet Loss";
opNames["kReorder"] = "Reorder Using Time Delay";
opNames["kReorderPI"] = "Reorder Using Packet Interval";
opNames["kDuplicate"] = "Packet Duplication";
opNames["kBandwidth"] = "General Settings";

Hashtable opBinds = new Hashtable();
Type typeObject = m_object.GetType();
opBinds["kDelay"] = typeObject.GetProperty("addDelay");
opBinds["kDrop"] = typeObject.GetProperty("addDrop");
opBinds["kDropSequence"] = typeObject.GetProperty("addDropSequence");
opBinds["kReorder"] = typeObject.GetProperty("addReorder");
opBinds["kReorderPI"] = typeObject.GetProperty("addReorderPI");
opBinds["kDuplicate"] = typeObject.GetProperty("addDuplicate");
opBinds["kBandwidth"] = null;

ArrayList opDefaultOrder = new ArrayList();
opDefaultOrder.Add("kDelay");
opDefaultOrder.Add("kDrop");
opDefaultOrder.Add("kDropSequence");
opDefaultOrder.Add("kReorder");
opDefaultOrder.Add("kReorderPI");
opDefaultOrder.Add("kDuplicate");
opDefaultOrder.Add("kBandwidth");

list.Items.Clear();
foreach (String key in ops)
{
    string name = opNames[key] as string;
    if (name == null) continue;
    opDefaultOrder.Remove(key);

    int i = list.Items.Add(name);
    bool chk = true;
    PropertyInfo prop = opBinds[key] as PropertyInfo;    
    if (prop != null)
    {
        chk = (bool) prop.GetValue(m_object, null);
    }
    list.SetItemChecked(i, chk);
}

foreach (String key in opDefaultOrder)
{
    string name = opNames[key] as string;
    if (name == null) continue;

    int i = list.Items.Add(name);
    bool chk = true;
    PropertyInfo prop = opBinds[key] as PropertyInfo;    
    if (prop != null)
    {
        chk = (bool) prop.GetValue(m_object, null);
    }
    list.SetItemChecked(i, chk);
}

if (list.Items.Count > 0)
{
    list.SelectedItem = list.Items[0];
}
